{% extends "_base/base.html.j2" %}

{# AGB-Muster — 10 Standard-Sektionen. Sprache: DE/EN. Default DE.
   Sections-Liste kann via data.sections überschrieben werden (Backend
   liefert eigene Texte), sonst werden Platzhalter-Texte gerendert. #}


{% block title %}{{ L.doc_title }} — {{ data.company.name | default('') }}{% endblock %}

{% set defaultSections = [
  ('scope',        'Diese Allgemeinen Geschäftsbedingungen (AGB) gelten für alle Verträge, die zwischen ' ~ data.company.name | default('uns') ~ ' und unseren Kunden geschlossen werden. Abweichende Bedingungen des Kunden werden nicht anerkannt, es sei denn, wir stimmen ihrer Geltung ausdrücklich schriftlich zu.'),
  ('contract',     'Die Darstellung der Waren in unserem Shop / Angebot stellt kein verbindliches Angebot dar. Mit Bestellung gibt der Kunde ein verbindliches Angebot zum Abschluss eines Kaufvertrags ab. Der Vertrag kommt zustande, wenn wir die Bestellung durch eine Auftragsbestätigung in Textform annehmen oder die Ware versenden.'),
  ('prices',       'Alle Preise verstehen sich in der jeweils gültigen Währung inkl. der gesetzlichen Umsatzsteuer und zuzüglich anfallender Versandkosten. Die Zahlung erfolgt nach Wahl des Kunden per Rechnung, Lastschrift, Kreditkarte oder den im Bestellprozess angebotenen Zahlungsdienstleistern. Bei Zahlung auf Rechnung ist der Rechnungsbetrag ohne Abzug innerhalb von 14 Tagen ab Rechnungsdatum fällig.'),
  ('delivery',     'Die Lieferung erfolgt an die vom Kunden angegebene Lieferadresse. Lieferfristen sind, sofern nicht ausdrücklich als verbindlich vereinbart, unverbindliche Richtwerte. Der Gefahrübergang erfolgt mit Übergabe der Ware an den Kunden bzw. an die von ihm beauftragte Transportperson.'),
  ('retention',    'Bis zur vollständigen Zahlung des Kaufpreises bleibt die gelieferte Ware unser Eigentum. Eine Weiterveräußerung, Verpfändung oder Sicherungsübereignung vor vollständiger Bezahlung ist nicht gestattet.'),
  ('warranty',     'Es gelten die gesetzlichen Gewährleistungsrechte. Bei Verbrauchern beträgt die Verjährungsfrist für Mängelansprüche zwei Jahre ab Lieferung; bei Unternehmern verkürzt sie sich auf zwölf Monate.'),
  ('liability',    'Wir haften unbeschränkt bei Vorsatz, grober Fahrlässigkeit, bei Verletzung von Leben, Körper oder Gesundheit sowie nach den Vorschriften des Produkthaftungsgesetzes. Im Übrigen ist die Haftung auf den vorhersehbaren, vertragstypischen Schaden begrenzt.'),
  ('odr',          'Die EU-Kommission stellt unter http://ec.europa.eu/consumers/odr/ eine Plattform zur Online-Streitbeilegung bereit. Wir sind nicht verpflichtet und nicht bereit, an einem Streitbeilegungsverfahren vor einer Verbraucherschlichtungsstelle teilzunehmen.'),
  ('jurisdiction', 'Gerichtsstand für alle Streitigkeiten aus diesem Vertragsverhältnis ist, soweit der Kunde Kaufmann, juristische Person des öffentlichen Rechts oder öffentlich-rechtliches Sondervermögen ist, unser Geschäftssitz. Es gilt das Recht der Bundesrepublik Deutschland unter Ausschluss des UN-Kaufrechts (CISG).'),
  ('severability', 'Sollten einzelne Bestimmungen dieser AGB ganz oder teilweise unwirksam sein oder werden, so wird hierdurch die Wirksamkeit der übrigen Bestimmungen nicht berührt. An die Stelle der unwirksamen Bestimmung tritt diejenige wirksame Regelung, die dem wirtschaftlichen Zweck der unwirksamen Bestimmung am nächsten kommt.'),
] %}

{% block content %}

  {# Pflicht-Disclaimer ganz oben — diese AGB sind ein generisches Muster,
     keine Anwaltsleistung, keine Rechtsberatung und nicht für den
     produktiven Einsatz freigegeben. Vor dem Verwenden in eigenen
     Verträgen / im Webshop von einem auf E-Commerce spezialisierten
     Juristen prüfen und an Geschäftsmodell + Jurisdiktion anpassen.
     Der Hinweis kann via `data.hideDisclaimer: true` ausgeblendet werden
     (z.B. wenn ein Anwalt die Vorlage finalisiert hat und sie dann
     produktiv ausgespielt wird). */ #}
  {% if not data.hideDisclaimer %}
  <section class="agb-disclaimer" role="note" aria-labelledby="agb-disclaimer-title">
    <div class="agb-disclaimer__title" id="agb-disclaimer-title">
      {% if _LANG == 'en' %}⚠ Sample only — not for productive use{% else %}⚠ Nur Muster — nicht produktiv verwenden{% endif %}
    </div>
    <p class="agb-disclaimer__body">
      {% if _LANG == 'en' %}
      This document is a generic terms-and-conditions scaffold provided as
      a starting point. It does <strong>not constitute legal advice</strong>
      and is <strong>not a substitute</strong> for review by a qualified
      lawyer. Wording, jurisdiction and industry-specific clauses must be
      adapted to your business and the applicable law before publication
      or contractual use. The author of this template assumes no
      liability for damages arising from its use without prior legal
      review.
      {% else %}
      Dieses Dokument ist ein generisches AGB-Muster und dient
      ausschließlich als Ausgangspunkt. Es stellt <strong>keine
      Rechtsberatung</strong> dar und ist <strong>kein Ersatz</strong>
      für die Prüfung durch eine zugelassene Anwältin oder einen
      zugelassenen Anwalt. Wortlaut, Gerichtsstand und branchen­
      spezifische Klauseln sind vor Veröffentlichung oder vertraglicher
      Verwendung an Geschäftsmodell und anwendbares Recht anzupassen.
      Für Schäden aus der Nutzung dieser Vorlage ohne vorherige
      Rechts­prüfung wird keine Haftung übernommen.
      {% endif %}
    </p>
  </section>
  {% endif %}

  <section class="box-subject agb-subject" data-box="subject">
    <h1>{{ L.doc_title }}</h1>
    <p class="agb-effective">{{ L.effective_date }} {{ data.effectiveDate }}</p>
    <p class="agb-company">{{ data.company.name }}{% if data.company.address %} · {{ data.company.address }}{% endif %}</p>
  </section>

  {% for key, fallback_body in defaultSections %}
  <section class="agb-section" aria-labelledby="agb-{{ key }}">
    <h2 id="agb-{{ key }}">{{ L.sec[key] }}</h2>
    <p>{{ ((data.sections or {})[key]) | default(fallback_body) }}</p>
  </section>
  {% endfor %}

  {# Footer mit den firmen-rechtlichen Pflichtangaben — Position, Adresse,
     Handelsregister, USt-ID, Geschäftsführer. Macht das Dokument selbst
     bei verlorener Briefkopfzeile rechtssicher zuordenbar. #}
  <section class="agb-footer" aria-labelledby="agb-footer-heading">
    <h2 id="agb-footer-heading" class="agb-footer__title">{{ data.company.name }}</h2>
    {% if data.company.address %}<p class="agb-footer__line">{{ data.company.address }}</p>{% endif %}
    <p class="agb-footer__meta">
      {% if data.company.ceo %}Geschäftsführer: {{ data.company.ceo }}{% endif %}
      {% if data.company.registrationCourt and data.company.registrationNumber %}
        {% if data.company.ceo %} · {% endif %}{{ data.company.registrationCourt }} {{ data.company.registrationNumber }}
      {% endif %}
      {% if data.company.vatId %}
        {% if data.company.ceo or data.company.registrationCourt %} · {% endif %}USt-ID: {{ data.company.vatId }}
      {% endif %}
    </p>
  </section>

{% endblock %}

css:
/* AGB-Muster — Briefkopf-ähnlich, mehrseitig. Paragraphen-Lesefluss
   priorisiert (Zeilenhöhe + Spalten-Breite). */

/* Pflicht-Disclaimer ganz oben — rot getöntes Warn-Banner,
   visuell unübersehbar. Mit Border-Left als Akzent + leichter
   Hintergrundtönung. */
.agb-disclaimer {
  margin: 0 0 8mm;
  padding: 4mm 6mm;
  border-left: 1.2mm solid #dc2626;
  background: rgba(239, 68, 68, 0.06);
  border-radius: 0 1.5mm 1.5mm 0;
  page-break-inside: avoid;
  page-break-after: avoid;
}
.agb-disclaimer__title {
  font-size: 10pt;
  font-weight: 700;
  color: #991b1b;
  margin-bottom: 2mm;
  text-transform: uppercase;
  letter-spacing: 0.3px;
}
.agb-disclaimer__body {
  font-size: 9.5pt;
  line-height: 1.5;
  color: #7f1d1d;
  margin: 0;
}

.agb-subject {
  margin-bottom: 6mm;
  padding-bottom: 4mm;
  border-bottom: 0.2mm solid #d1d5db;
}
.agb-subject h1 {
  font-size: 18pt;
  font-weight: 700;
  margin: 0;
  letter-spacing: -0.2pt;
}
.agb-effective {
  font-size: 10pt;
  color: #6b7280;
  margin: 1mm 0 0;
}
.agb-company {
  font-size: 10pt;
  color: #4b5563;
  margin: 1mm 0 0;
}

.agb-section {
  margin: 6mm 0;
  page-break-inside: avoid;
}
.agb-section h2 {
  font-size: 11pt;
  font-weight: 700;
  margin: 0 0 1.5mm;
  color: #111827;
}
.agb-section p {
  font-size: 10pt;
  line-height: 1.55;
  text-align: justify;
  hyphens: auto;
  -webkit-hyphens: auto;
  margin: 0;
  color: #1f2937;
}

.agb-footer {
  margin-top: 10mm;
  padding-top: 4mm;
  border-top: 0.2mm solid #d1d5db;
  font-size: 9pt;
  color: #6b7280;
  page-break-inside: avoid;
}
.agb-footer__title {
  font-size: 9pt;
  font-weight: 700;
  letter-spacing: 0.3px;
  text-transform: uppercase;
  color: #9ca3af;
  margin: 0 0 1mm;
}
.agb-footer__line { margin: 0.5mm 0; }
.agb-footer__meta { margin: 1.5mm 0 0; }
